// 关键词搜索(支持中英文模糊匹配)
export function searchFood(query) {
  const q = (query || '').toLowerCase().trim();
  if (!q) return [];
  return Object.entries(NUTRITION_DB)
    .filter(([id, food]) => {
      if (id === 'generic_meal') return false;
      return id.includes(q) ||
             food.zh.toLowerCase().includes(q) ||
             food.en.toLowerCase().includes(q);
    })
    .map(([id, food]) => ({ id, ...food }));
}

// 获取所有食物
export function getAllFoods() {
  return Object.entries(NUTRITION_DB).map(([id, food]) => ({ id, ...food }));
}

// 按 id 获取
export function getFoodById(id) {
  const food = NUTRITION_DB[id];
  if (!food) return null;
  return { id, ...food };
}
